-- Cotizador PLUS — Seed catįlogos (tableros + cantos) desde Excel Materiales
-- TABLEROS (Tabla13)
on conflict (codigo) do update set proveedor=excluded.proveedor, espesor_mm=excluded.espesor_mm, sustrato=excluded.sustrato, color_nombre=excluded.color_nombre, formato=excluded.formato, area_m2=excluded.area_m2, precio=excluded.precio, descuento=excluded.descuento, precio_real=excluded.precio_real, precio_m2=excluded.precio_m2, notas=excluded.notas, actualizado=excluded.actualizado, updated_at=now();

-- CANTOS (Tabla2)
on conflict (codigo) do update set referencia=excluded.referencia, calibre=excluded.calibre, precio=excluded.precio, actualizado=excluded.actualizado, updated_at=now();
